def calculate_mrr(rankings):
    # rankings: list of ranks of the first correct answer
    total_rr = 0
    for rank in rankings:
        if rank > 0:
            total_rr += 1.0 / rank
    return round(total_rr / len(rankings), 3)

# Test session: Q1 found at #1, Q2 found at #3, Q3 not found
test_ranks = [1, 3, 0]
print(f"System MRR: {calculate_mrr(test_ranks)}")
